39	// Median of a vector (mutates order via nth_element). Empty -> NaN.
40	double median_inplace(std::vector<double> & v)
41	{
42	  const size_t n = v.size();
43	  if (n == 0) {
44	    return std::numeric_limits<double>::quiet_NaN();
45	  }
46	  const size_t mid = n / 2;
47	  std::nth_element(v.begin(), v.begin() + mid, v.end());
48	  const double hi = v[mid];
49	  if (n % 2 == 1) {
50	    return hi;
51	  }
52	  // even: average of the two central order statistics (matches numpy.median)
53	  const double lo = *std::max_element(v.begin(), v.begin() + mid);
54	  return 0.5 * (lo + hi);
55	}
