174	    max_depth_age_ = declare_parameter<double>("max_depth_age", 0.4);
175	    transform_tolerance_ = declare_parameter<double>("transform_tolerance", 0.2);
176	    lidar_trust_margin_ = declare_parameter<double>("lidar_trust_margin", 0.0);
