182	    hfov_ = deg2rad(declare_parameter<double>("hfov_deg", 73.0));
183	    vfov_ = deg2rad(declare_parameter<double>("vfov_deg", 58.0));
184	
185	    // --- ground (floor) detection ---
186	    ground_estimation_ = declare_parameter<bool>("ground_estimation", true);
187	    ground_row_margin_ = declare_parameter<int>("ground_row_margin", 10);
188	    ground_max_range_ = declare_parameter<double>("ground_max_range", 4.0);
