236	private:
237	  static double deg2rad(double d) {return d * M_PI / 180.0;}
238	
239	  // ------------------------------------------------------------------ info
240	  void infoCb(const sensor_msgs::msg::CameraInfo::SharedPtr msg)
241	  {
242	    const auto & k = msg->k;  // row-major 3x3
243	    if (k[0] > 0.0 && k[4] > 0.0) {
244	      ci_w_ = static_cast<int>(msg->width);
245	      ci_h_ = static_cast<int>(msg->height);
246	      ci_fx_ = k[0]; ci_fy_ = k[4]; ci_cx_ = k[2]; ci_cy_ = k[5];
247	      have_ci_ = true;
248	    }
249	  }
