251	  // Pick intrinsics for a w x h depth image (priority: params > matching
252	  // camera_info > FOV pinhole). Mirrors _resolve_intrinsics.
253	  void resolveIntrinsics(int w, int h, double & fx, double & fy, double & cx, double & cy)
254	  {
255	    std::string src;
256	    if (param_fx_ > 0.0 && param_fy_ > 0.0) {
257	      src = "params";
258	      fx = param_fx_; fy = param_fy_; cx = param_cx_; cy = param_cy_;
259	    } else if (have_ci_ && ci_w_ == w && ci_h_ == h) {
260	      src = "camera_info";
261	      fx = ci_fx_; fy = ci_fy_; cx = ci_cx_; cy = ci_cy_;
262	    } else {
263	      src = "fov";
264	      cx = w / 2.0; cy = h / 2.0;
265	      fx = (w / 2.0) / std::tan(hfov_ / 2.0);
266	      fy = (h / 2.0) / std::tan(vfov_ / 2.0);
267	    }
268	    if (intr_src_ != src) {
269	      RCLCPP_INFO(
270	        get_logger(), "intrinsics source=%s: fx=%.1f fy=%.1f cx=%.1f cy=%.1f for depth %dx%d.",
271	        src.c_str(), fx, fy, cx, cy, w, h);
272	      if (src == "fov" && have_ci_) {
273	        RCLCPP_WARN(
274	          get_logger(), "camera_info %dx%d != depth %dx%d; using FOV model (hfov=%.0f vfov=%.0f deg).",
275	          ci_w_, ci_h_, w, h, hfov_ * 180.0 / M_PI, vfov_ * 180.0 / M_PI);
276	      }
277	      intr_src_ = src;
278	    }
279	  }
280	
281	  // ---------------------------------------------------------------- ground
282	  // Estimate the floor line v = A*(1/z) + B from this frame (A = h_cam*fy,
283	  // B ~= cy). Per-row median inverse depth -> robust line -> EMA -> coast ->
284	  // assumed-model fallback. Mirrors _ground_plane. z is row-major h*w (metres).
285	  void groundPlane(const std::vector<float> & z, int h, int w, double fy, double cy,
286	    double & outA, double & outB)
287	  {
288	    const double A0 = camera_height_ * fy;
289	    const double B0 = cy;
290	    if (!ground_estimation_) {
291	      outA = A0; outB = B0;
292	      return;
293	    }
294	    const int rows = h;
295	    int v0 = static_cast<int>(cy) + ground_row_margin_;
296	    v0 = std::max(0, std::min(v0, rows - 2));
297	
298	    // candidate rows: >= ground_min_row_px valid pixels in [range_min, ground_max_range)
299	    std::vector<int> idx;          // absolute row indices (v0..rows-1)
300	    std::vector<double> xx;        // per-row median(1/z)
301	    for (int v = v0; v < rows; ++v) {
302	      const float * row = &z[static_cast<size_t>(v) * w];
303	      std::vector<double> inv;
304	      inv.reserve(w);
305	      for (int u = 0; u < w; ++u) {
306	        const float zz = row[u];
307	        if (zz > range_min_ && zz < ground_max_range_) {
308	          inv.push_back(static_cast<double>(1.0f / zz));  // float32 reciprocal (numpy)
309	        }
310	      }
311	      if (static_cast<int>(inv.size()) >= ground_min_row_px_) {
312	        double m = median_inplace(inv);
313	        m = static_cast<double>(static_cast<float>(m));   // float32 median (numpy nanmedian)
314	        if (std::isfinite(m)) {
315	          idx.push_back(v);
316	          xx.push_back(m);
317	        }
318	      }
319	    }
320	
321	    bool good = false;
322	    LineFit lf;
323	    if (static_cast<int>(idx.size()) >= ground_min_rows_) {
324	      std::vector<double> yy(idx.size());
325	      for (size_t i = 0; i < idx.size(); ++i) {
326	        yy[i] = static_cast<double>(idx[i]);
327	      }
328	      lf = robust_line(xx, yy);
329	      good = lf.ok &&
330	        (lf.ninl >= ground_min_rows_ * 0.5) &&   // float threshold, matches Python (no int trunc)
331	        (ground_h_lo_ * fy < lf.A) && (lf.A < ground_h_hi_ * fy);
332	    }
333	
334	    if (good) {
335	      if (!have_ground_) {
336	        ground_A_ = lf.A; ground_B_ = lf.B; have_ground_ = true;
337	      } else {
338	        const double a = ground_ema_;
339	        ground_A_ = (1.0 - a) * ground_A_ + a * lf.A;
340	        ground_B_ = (1.0 - a) * ground_B_ + a * lf.B;
341	      }
342	      ground_fail_ = 0;
343	      if (ground_src_ != "fit") {
344	        RCLCPP_INFO(
345	          get_logger(), "ground: data-driven fit ON (h_cam~%.3f m, B~%.0f px)",
346	          ground_A_ / fy, ground_B_);
347	        ground_src_ = "fit";
348	      }
349	      outA = ground_A_; outB = ground_B_;
350	      return;
351	    }
352	    // fit failed this frame: coast on last good, else fall back to assumed model
353	    ++ground_fail_;
354	    if (have_ground_ && ground_fail_ <= ground_fail_max_) {
355	      outA = ground_A_; outB = ground_B_;
356	      return;
357	    }
358	    if (ground_src_ != "assumed") {
359	      RCLCPP_WARN(
360	        get_logger(), "ground: floor not reliably visible -> assumed model (h_cam=%.3f, cy=%.0f)",
361	        camera_height_, cy);
362	      ground_src_ = "assumed";
363	    }
364	    outA = A0; outB = B0;
365	  }
366	
367	  // Detect ledge/stair edges where the expected floor returns nothing. Appends
368	  // (u,v,z) edge points to the out vectors. Mirrors _drop_edges. `valid` is the
369	  // per-pixel (z>range_min && z<range_max) mask, row-major h*w.
370	  void dropEdges(const std::vector<float> & z, const std::vector<uint8_t> & valid,
371	    int h, int w, double A, double B,
372	    std::vector<float> & out_u, std::vector<float> & out_v, std::vector<float> & out_z)
373	  {
374	    std::vector<uint8_t> seen(w, 0), done(w, 0);
375	    std::vector<int> miss(w, 0), lastv(w, -1), edge(w, -1);
376	    const double gap = drop_gap_;
377	    for (int v = h - 1; v >= 1; --v) {
378	      const double denom = static_cast<double>(v) - B;
379	      if (denom <= 1.0) {       // at/above the floor horizon
380	        break;
381	      }
382	      const double zexp = A / denom;
383	      if (zexp <= range_min_) {
384	        continue;
385	      }
386	      if (zexp >= drop_check_range_) {  // past the drop horizon (only farther up)
387	        break;
388	      }
389	      const double tol = drop_floor_tol_abs_ + drop_floor_tol_rel_ * zexp;
390	      // float32 thresholds mirroring numpy's NEP weak promotion: array-scalar
391	      // (row-zexp, <=tol) narrows the scalar first; scalar-scalar (zexp-tol,
392	      // zexp+tol+gap) computes in float64 then narrows to float32.
393	      const float zexpf = static_cast<float>(zexp);
394	      const float tolf = static_cast<float>(tol);
395	      const float nearer_thr = static_cast<float>(zexp - tol);
396	      const float missing_thr = static_cast<float>(zexp + tol + gap);
397	      const float * row = &z[static_cast<size_t>(v) * w];
398	      const uint8_t * vrow = &valid[static_cast<size_t>(v) * w];
399	      for (int u = 0; u < w; ++u) {
400	        if (done[u]) {
401	          continue;
402	        }
403	        const bool vok = vrow[u] != 0;
404	        const float rv = row[u];
405	        const bool present = vok && (std::abs(rv - zexpf) <= tolf);
406	        const bool nearer = vok && (rv < nearer_thr);
407	        const bool missing = (!vok) || (vok && (rv > missing_thr));
408	        if (nearer) {           // occluder in front of floor ends the search
409	          done[u] = 1;
410	          continue;
411	        }
412	        // active (== !done) is implied here
413	        if (present) {
414	          miss[u] = 0;
415	          lastv[u] = v;
416	          seen[u] = 1;
417	        } else if (missing && seen[u]) {
418	          ++miss[u];
419	          if (miss[u] >= drop_min_missing_rows_ && lastv[u] >= 0) {
420	            edge[u] = lastv[u];
421	            done[u] = 1;
422	          }
423	        }
424	      }
425	    }
426	    for (int u = 0; u < w; ++u) {
427	      if (edge[u] >= 0) {
428	        const double dv = static_cast<double>(edge[u]);
429	        const double dz = A / (dv - B);
430	        out_u.push_back(static_cast<float>(u));
431	        out_v.push_back(static_cast<float>(dv));
432	        out_z.push_back(static_cast<float>(dz));
433	      }
434	    }
435	  }
436	
437	  // ---------------------------------------------------------------- extrinsics
438	  bool ensureExtrinsics()
439	  {
440	    if (have_extr_) {
441	      return true;
442	    }
443	    if (optical_frame_.empty() || scan_frame_.empty()) {
444	      return false;
445	    }
446	    geometry_msgs::msg::TransformStamped tf;
447	    try {
448	      tf = tf_buffer_->lookupTransform(
449	        scan_frame_, optical_frame_, tf2::TimePointZero,
450	        tf2::durationFromSec(transform_tolerance_));
451	    } catch (const tf2::TransformException & e) {
452	      if (!warned_no_tf_) {
453	        RCLCPP_WARN(get_logger(), "waiting for TF %s<-%s: %s",
454	          scan_frame_.c_str(), optical_frame_.c_str(), e.what());
455	        warned_no_tf_ = true;
456	      }
457	      return false;
458	    }
459	    const auto & q = tf.transform.rotation;
460	    const double x = q.x, y = q.y, zq = q.z, w = q.w;
461	    R_[0][0] = 1 - 2 * (y * y + zq * zq); R_[0][1] = 2 * (x * y - zq * w);     R_[0][2] = 2 * (x * zq + y * w);
462	    R_[1][0] = 2 * (x * y + zq * w);      R_[1][1] = 1 - 2 * (x * x + zq * zq); R_[1][2] = 2 * (y * zq - x * w);
463	    R_[2][0] = 2 * (x * zq - y * w);      R_[2][1] = 2 * (y * zq + x * w);      R_[2][2] = 1 - 2 * (x * x + y * y);
464	    t_[0] = tf.transform.translation.x;
465	    t_[1] = tf.transform.translation.y;
466	    t_[2] = tf.transform.translation.z;
467	    have_extr_ = true;
468	    RCLCPP_INFO(get_logger(), "extrinsics %s<-%s cached (t=[%.3f,%.3f,%.3f]).",
469	      scan_frame_.c_str(), optical_frame_.c_str(), t_[0], t_[1], t_[2]);
470	    return true;
471	  }
472	
473	  // ----------------------------------------------------------------- depth
474	  void depthCb(const sensor_msgs::msg::Image::SharedPtr msg)
475	  {
476	    optical_frame_ = msg->header.frame_id;
477	    if (!ensureExtrinsics()) {
478	      return;
479	    }
480	    const int w = static_cast<int>(msg->width);
481	    const int h = static_cast<int>(msg->height);
482	    if (w <= 0 || h <= 0) {
483	      return;
484	    }
485	    double fx, fy, cx, cy;
486	    resolveIntrinsics(w, h, fx, fy, cx, cy);
487	
488	    // 16UC1 millimetres -> metres. Row stride = msg->step bytes; take first w cols.
489	    const size_t step = msg->step;
490	    std::vector<float> z(static_cast<size_t>(h) * w);
491	    const uint8_t * data = msg->data.data();
492	    const bool swap = msg->is_bigendian != 0;
493	    for (int v = 0; v < h; ++v) {
494	      const uint8_t * rp = data + static_cast<size_t>(v) * step;
495	      float * zr = &z[static_cast<size_t>(v) * w];
496	      for (int u = 0; u < w; ++u) {
497	        uint16_t mm = static_cast<uint16_t>(rp[2 * u]) |
498	          (static_cast<uint16_t>(rp[2 * u + 1]) << 8);
499	        if (swap) {
500	          mm = static_cast<uint16_t>((mm >> 8) | (mm << 8));
501	        }
502	        zr[u] = mm * 0.001f;
503	      }
504	    }
505	
506	    double A, B;
507	    groundPlane(z, h, w, fy, cy, A, B);
508	
509	    // height above the FITTED floor = (A + (B - v)*z)/fy
510	    // keep/valid masks; per-column vertical collapse (nearest kept pixel).
511	    // float32 band constants (mirror numpy's float32 height arithmetic)
512	    const float Af = static_cast<float>(A), Bf = static_cast<float>(B);
513	    const float fyf = static_cast<float>(fy);
514	    const float minhf = static_cast<float>(min_h_), maxhf = static_cast<float>(max_h_);
515	    const float negdropf = static_cast<float>(drop_max_depth_);
516	    const float rminf = static_cast<float>(range_min_), rmaxf = static_cast<float>(range_max_);
517	    std::vector<uint8_t> valid(static_cast<size_t>(h) * w, 0);
518	    std::vector<float> col_min(w, kInf);
519	    std::vector<int> col_row(w, -1);
520	    for (int v = 0; v < h; ++v) {
521	      const float * zr = &z[static_cast<size_t>(v) * w];
522	      uint8_t * vr = &valid[static_cast<size_t>(v) * w];
523	      const float vf = static_cast<float>(v);
524	      for (int u = 0; u < w; ++u) {
525	        const float zz = zr[u];
526	        const bool vv = (zz > rminf) && (zz < rmaxf);   // float32 bounds (numpy parity)
527	        vr[u] = vv ? 1 : 0;
528	        // height above the fitted floor, in float32 to match numpy: (A+(B-v)*z)/fy
529	        const float height = ((Bf - vf) * zz + Af) / fyf;
530	        const bool pos = (height > minhf) && (height < maxhf);
531	        bool keep;
532	        if (drop_detection_) {
533	          const bool neg = (height < -minhf) && (height > -negdropf);
534	          keep = vv && (pos || neg);
535	        } else {
536	          keep = vv && pos;
537	        }
538	        if (keep && zz < col_min[u]) {   // strict < => first row wins ties (argmin)
539	          col_min[u] = zz;
540	          col_row[u] = v;
541	        }
542	      }
543	    }
544	
545	    // surviving collapse points
546	    std::vector<float> uc, vc, zc;
547	    uc.reserve(w);
548	    vc.reserve(w);
549	    zc.reserve(w);
550	    for (int u = 0; u < w; ++u) {
551	      if (std::isfinite(col_min[u]) && col_row[u] >= 0) {
552	        uc.push_back(static_cast<float>(u));
553	        vc.push_back(static_cast<float>(col_row[u]));
554	        zc.push_back(col_min[u]);
555	      }
556	    }
557	
558	    // drops: append the near edges of ledges
559	    if (drop_detection_) {
560	      dropEdges(z, valid, h, w, A, B, uc, vc, zc);
561	    }
562	
563	    if (uc.empty()) {
564	      have_depth_ = false;
565	      return;
566	    }
567	
568	    // back-project to optical frame, then static extrinsic into the lidar frame
569	    // (only x,y matter for a planar scan); store range/bearing of each point.
570	    const float cxf = static_cast<float>(cx), cyf = static_cast<float>(cy);
571	    const float fxf = static_cast<float>(fx);   // fyf already in scope from the collapse loop
572	    std::vector<float> rng(uc.size()), brg(uc.size());
573	    for (size_t i = 0; i < uc.size(); ++i) {
574	      // float32 throughout to mirror numpy (R_/t_ are float; zc/uc/vc float)
575	      const float zi = zc[i];
576	      const float xo = (uc[i] - cxf) * zi / fxf;
577	      const float yo = (vc[i] - cyf) * zi / fyf;
578	      const float xl = R_[0][0] * xo + R_[0][1] * yo + R_[0][2] * zi + t_[0];
579	      const float yl = R_[1][0] * xo + R_[1][1] * yo + R_[1][2] * zi + t_[1];
580	      rng[i] = std::hypot(xl, yl);
581	      brg[i] = std::atan2(yl, xl);
582	    }
583	    depth_rng_ = std::move(rng);
584	    depth_brg_ = std::move(brg);
585	    depth_stamp_ = rclcpp::Time(msg->header.stamp);
586	    have_depth_ = true;
587	  }
