589	  // ------------------------------------------------------------------ scan
590	  void scanCb(const sensor_msgs::msg::LaserScan::SharedPtr msg)
591	  {
592	    scan_frame_ = msg->header.frame_id;
593	    const size_t n = msg->ranges.size();
594	    std::vector<float> fused(msg->ranges.begin(), msg->ranges.end());
595	
596	    std::vector<float> dmin;
597	    const bool have = depthProfile(*msg, n, dmin);
598	    if (have) {
599	      for (size_t i = 0; i < n; ++i) {
600	        float lid = fused[i];
601	        if (!std::isfinite(lid) || lid <= msg->range_min) {
602	          lid = kInf;   // lidar no-return -> empty beam
603	        }
604	        // depth overrides only when nearer than the lidar (by >= margin) or empty beam
605	        if (dmin[i] < lid - static_cast<float>(lidar_trust_margin_)) {
606	          fused[i] = dmin[i];
607	        }
608	      }
609	      if (dbg_pub_) {
610	        publishLike(*msg, dmin, dbg_pub_);
611	      }
612	    }
613	    publishLike(*msg, fused, scan_pub_);
614	  }
