616	  // Bin the cached collapsed depth onto this scan's beam grid (min per beam).
617	  // Returns false (and leaves dmin untouched) if no fresh, in-band depth.
618	  bool depthProfile(const sensor_msgs::msg::LaserScan & scan, size_t n,
619	    std::vector<float> & dmin)
620	  {
621	    if (!have_depth_) {
622	      return false;
623	    }
624	    const double age =
625	      (rclcpp::Time(scan.header.stamp) - depth_stamp_).seconds();
626	    if (std::abs(age) > max_depth_age_) {
627	      return false;
628	    }
629	    const float amin = scan.angle_min, amax = scan.angle_max;
630	    const float rmin = scan.range_min, rmax = scan.range_max;
631	    const float ainc = scan.angle_increment;
632	    std::vector<float> out(n, kInf);
633	    bool any = false;
634	    for (size_t i = 0; i < depth_brg_.size(); ++i) {
635	      const float b = depth_brg_[i];
636	      const float r = depth_rng_[i];
637	      if (b >= amin && b <= amax && r >= rmin && r <= rmax) {
638	        // np.round = round-half-to-even; std::lrint matches (default FE_TONEAREST)
639	        long idx = std::lrint((b - amin) / ainc);
640	        if (idx < 0) {
641	          idx = 0;
642	        } else if (idx > static_cast<long>(n) - 1) {
643	          idx = static_cast<long>(n) - 1;
644	        }
645	        if (r < out[idx]) {
646	          out[idx] = r;
647	        }
648	        any = true;
649	      }
650	    }
651	    if (!any) {
652	      return false;
653	    }
654	    dmin = std::move(out);
655	    return true;
656	  }
