1	// container_node.cpp
2	//
3	// Single-process component container for the three C++ guide_mate nodes. The
4	// whole point is ONE shared tf2_ros::Buffer + a SINGLE TransformListener feeding
5	// all three nodes -- so the busy /tf stream is deserialized ONCE instead of
6	// three times (the duplicate-TF cost that made running them as separate
7	// processes expensive). C++ (no GIL) also lets the MultiThreadedExecutor run
8	// their callbacks on separate cores.
9	//
10	// The three node classes are pulled in with GUIDE_MATE_CONTAINER defined, which
11	// suppresses each file's own main(); each node still builds as its own
12	// standalone executable (where the macro is NOT defined) and creates its own TF
13	// buffer/listener there.
14	//
15	// Launch namespaced with the /tf remaps so the single listener reads the robot's
16	// namespaced TF tree:
17	//   ros2 run guide_mate_perception guide_mate_container
18	//     --ros-args -r __ns:=/turtlebot468 -r /tf:=tf -r /tf_static:=tf_static
19	#define GUIDE_MATE_CONTAINER
20	#include "depth_lidar_fusion_node.cpp"  // class DepthLidarFusion (main suppressed)
21	#include "bfs_explorer_node.cpp"        // class BfsExplorer
22	#include "glass_guard_node.cpp"         // class GlassGuard
23	
24	#include <memory>
25	
26	#include <rclcpp/rclcpp.hpp>
27	#include <tf2_ros/buffer.h>
28	#include <tf2_ros/transform_listener.h>
29	
30	int main(int argc, char ** argv)
31	{
32	  rclcpp::init(argc, argv);
33	
34	  // A dedicated node owns the ONE TransformListener; its Buffer is shared with
35	  // all three nodes, which therefore create NO listener of their own.
36	  auto tf_node = std::make_shared<rclcpp::Node>("guide_mate_perception_tf");
37	  auto buffer = std::make_shared<tf2_ros::Buffer>(tf_node->get_clock());
38	  auto listener = std::make_shared<tf2_ros::TransformListener>(*buffer, tf_node);
39	
40	  auto fusion = std::make_shared<DepthLidarFusion>(buffer);
41	  auto bfs = std::make_shared<BfsExplorer>(buffer);
42	  auto guard = std::make_shared<GlassGuard>(buffer);
43	
44	  rclcpp::executors::MultiThreadedExecutor executor;
45	  executor.add_node(tf_node);
46	  executor.add_node(fusion);
47	  executor.add_node(bfs);
48	  executor.add_node(guard);
49	
50	  RCLCPP_INFO(rclcpp::get_logger("guide_mate_container"),
51	    "guide_mate container up: depth_lidar_fusion + bfs_explorer + glass_guard in "
52	    "ONE process sharing ONE TF listener.");
53	
54	  executor.spin();
55	  rclcpp::shutdown();
56	  return 0;
57	}
